    console.log("[v0] updatedWorkout returned:", updatedWorkout ? "exists" : "null")

    if (updatedWorkout) {
      const exercise = updatedWorkout.exercises.find((ex) => ex.id === exerciseId)
      const set = exercise?.sets.find((s) => s.id === setId)
