    setRestTimer(Date.now())
    setRestTimeLeft(restSeconds)
  }

  const parseRestDuration = (duration: string): number => {
    const match = duration.match(/(\d+)/)
    return match ? Number.parseInt(match[1]) * 60 : 120
  }

